    private void modifyServerStringInComments(String apname, String originalServer, String targetServer) {
        BDBWorker worker = new BDBWorker(apname);
        try{
            SDBQuery q = new SDBQueryFull(worker);
            q.go(DConst.COMMENT_CONTENT);
            SDBNode node;
            while((node=q.next())!=null){
                String value=node.getValue();
                if(value.contains(originalServer)){
                    worker.updateNode(DConst.COMMENT_CONTENT,node.getId(),value.replaceAll(originalServer, targetServer));
                }
            }
        }
        finally {
            worker.commit();
        }
    }

